def _strip_prefix(state_dict: Dict[str, torch.Tensor], prefixes: Tuple[str, ...] = ("module.", "model.", "net.")) -> Dict[str, torch.Tensor]:
    out = {}
    for k, v in state_dict.items():
        nk = k
